package main

import (
	"crypto/rand"
	"encoding/base64"
	"fmt"
)

func GenerateSessionToken() (string, error) {
	bytes := make([]byte, 24)
	_, err := rand.Read(bytes)
	if err != nil {
		return "", fmt.Errorf("failed to generate random bytes: %w", err)
	}
	
	token := base64.URLEncoding.EncodeToString(bytes)
	return token[:32], nil
}